var rows = (rawData.rows || []).slice();
rows.sort(function(a, b) { return new Date(a.t) - new Date(b.t); });

var times = [];
var candles = [];
var lows = [];
var highs = [];

rows.forEach(function(r) {
  var o = +r.o, h = +r.h, l = +r.l, c = +r.c;
  times.push(r.t);
  candles.push([o, c, l, h]);
  lows.push(l);
  highs.push(h);
});

var priceMin = Math.min.apply(null, lows);
var priceMax = Math.max.apply(null, highs);
var span = priceMax - priceMin;
if (!isFinite(span) || span <= 0) span = 1;

var binTarget = Math.min(24, Math.max(12, rows.length));
var rawBin = span / binTarget;
var pow = Math.pow(10, Math.floor(Math.log(rawBin) / Math.LN10));
var steps = [1, 2, 2.5, 5, 10];
var binSize = steps[steps.length - 1] * pow;
for (var i = 0; i < steps.length; i++) {
  if (steps[i] * pow >= rawBin) {
    binSize = steps[i] * pow;
    break;
  }
}

var start = Math.floor(priceMin / binSize) * binSize;
var end = Math.ceil(priceMax / binSize) * binSize;
var bins = [];
for (var p = start; p < end - 1e-12; p += binSize) {
  var b0 = +p.toFixed(6);
  var b1 = +(p + binSize).toFixed(6);
  bins.push({ start: b0, end: b1, center: +((b0 + b1) / 2).toFixed(6), vol: 0 });
}

rows.forEach(function(r) {
  var h = +r.h, l = +r.l, c = +r.c, v = +r.v;
  if (!isFinite(v) || v < 0) v = 0;

  if (h === l) {
    var idx = Math.max(0, Math.min(bins.length - 1, Math.floor((c - start) / binSize)));
    bins[idx].vol += v;
    return;
  }

  var totalRange = h - l;
  bins.forEach(function(bin) {
    var overlap = Math.max(0, Math.min(h, bin.end) - Math.max(l, bin.start));
    if (overlap > 0) {
      bin.vol += v * (overlap / totalRange);
    }
  });
});

var profileMax = 0;
var pocIndex = 0;
bins.forEach(function(bin, i) {
  if (bin.vol > profileMax) {
    profileMax = bin.vol;
    pocIndex = i;
  }
});

var totalProfileVol = bins.reduce(function(s, b) { return s + b.vol; }, 0);
var target = totalProfileVol * 0.7;
var left = pocIndex;
var right = pocIndex;
var accum = bins[pocIndex] ? bins[pocIndex].vol : 0;

while (accum < target && (left > 0 || right < bins.length - 1)) {
  var leftVol = left > 0 ? bins[left - 1].vol : -1;
  var rightVol = right < bins.length - 1 ? bins[right + 1].vol : -1;
  if (rightVol > leftVol) {
    right++;
    accum += bins[right].vol;
  } else {
    left--;
    accum += bins[left].vol;
  }
}

var pocPrice = bins[pocIndex] ? bins[pocIndex].center : null;
var vah = bins[right] ? bins[right].end : null;
var val = bins[left] ? bins[left].start : null;

var profileData = bins.map(function(bin, i) {
  return [
    bin.start,
    bin.end,
    +bin.vol.toFixed(2),
    i === pocIndex ? 1 : 0,
    i >= left && i <= right ? 1 : 0,
    bin.center
  ];
});

var pad = binSize * 1.5;
transformedData = {
  times: times,
  candles: candles,
  profileData: profileData,
  priceMin: +(start - pad).toFixed(6),
  priceMax: +(end + pad).toFixed(6),
  profileMax: +profileMax.toFixed(2),
  pocPrice: pocPrice,
  vah: vah,
  val: val,
  binSize: binSize
};

echarts_js:
option = {
  animation: false,
  title: {
    text: 'Candlestick + Volume Profile',
    left: 'center',
    top: 8
  },
  legend: {
    top: 36,
    data: ['価格', '終値', 'Volume Profile']
  },
  axisPointer: {
    link: [{ yAxisIndex: [0, 1] }]
  },
  tooltip: {
    trigger: 'axis',
    axisPointer: {
      type: 'cross'
    },
    formatter: function(params) {
      var list = Array.isArray(params) ? params : [params];
      var candle = null;
      for (var i = 0; i < list.length; i++) {
        if (list[i].seriesName === '価格') {
          candle = list[i];
          break;
        }
      }
      if (!candle || !candle.data) return '';
      var d = candle.data;
      return [
        candle.axisValueLabel,
        'Open: ' + d[0],
        'High: ' + d[3],
        'Low: ' + d[2],
        'Close: ' + d[1]
      ].join('<br/>');
    }
  },
  grid: [
    {
      left: '9%',
      right: '31%',
      top: 84,
      bottom: 36,
      containLabel: true
    },
    {
      right: '7%',
      width: '20%',
      top: 84,
      bottom: 36
    }
  ],
  xAxis: [
    {
      type: 'category',
      gridIndex: 0,
      data: transformedData.times,
      boundaryGap: true,
      axisLine: { onZero: false },
      splitLine: { show: false },
      min: 'dataMin',
      max: 'dataMax'
    },
    {
      type: 'value',
      gridIndex: 1,
      min: 0,
      max: transformedData.profileMax * 1.1,
      inverse: true,
      position: 'top',
      axisLine: { show: false },
      axisTick: { show: false },
      axisLabel: { show: false },
      splitLine: { show: false }
    }
  ],
  yAxis: [
    {
      type: 'value',
      gridIndex: 0,
      scale: true,
      min: transformedData.priceMin,
      max: transformedData.priceMax,
      splitNumber: 8,
      axisLabel: {
        formatter: function(v) { return v.toFixed(1); }
      },
      splitLine: {
        show: true,
        lineStyle: { opacity: 0.35 }
      }
    },
    {
      type: 'value',
      gridIndex: 1,
      scale: true,
      min: transformedData.priceMin,
      max: transformedData.priceMax,
      splitNumber: 8,
      axisLine: { show: false },
      axisTick: { show: false },
      axisLabel: { show: false },
      splitLine: { show: false }
    }
  ],
  dataZoom: [
    {
      type: 'inside',
      xAxisIndex: [0],
      start: 0,
      end: 100
    },
    {
      type: 'inside',
      yAxisIndex: [0, 1],
      start: 0,
      end: 100
    }
  ],
  series: [
    {
      name: '価格',
      type: 'candlestick',
      xAxisIndex: 0,
      yAxisIndex: 0,
      data: transformedData.candles,
      itemStyle: {
        color: '#ef5350',
        color0: '#26a69a',
        borderColor: '#ef5350',
        borderColor0: '#26a69a'
      },
      markLine: {
        symbol: ['none', 'none'],
        label: { show: true },
        lineStyle: { type: 'dashed', width: 1.2 },
        data: [
          {
            name: 'POC',
            yAxis: transformedData.pocPrice,
            lineStyle: { color: '#d14a61', width: 2 }
          },
          {
            name: 'VAH',
            yAxis: transformedData.vah,
            lineStyle: { color: '#5470c6', width: 1.5 }
          },
          {
            name: 'VAL',
            yAxis: transformedData.val,
            lineStyle: { color: '#5470c6', width: 1.5 }
          }
        ]
      }
    },
    {
      name: '終値',
      type: 'line',
      xAxisIndex: 0,
      yAxisIndex: 0,
      data: transformedData.candles.map(function(v) { return v[1]; }),
      symbol: 'none',
      smooth: false,
      lineStyle: {
        width: 1,
        opacity: 0.35
      }
    },
    {
      name: 'Volume Profile',
      type: 'custom',
      xAxisIndex: 1,
      yAxisIndex: 1,
      data: transformedData.profileData,
      tooltip: {
        trigger: 'item',
        formatter: function(p) {
          var d = p.data;
          return [
            'Price Range: ' + d[0].toFixed(2) + ' - ' + d[1].toFixed(2),
            'Volume: ' + Math.round(d[2]),
            d[3] ? 'POC' : '',
            d[4] ? 'Value Area' : ''
          ].filter(Boolean).join('<br/>');
        }
      },
      renderItem: function(params, api) {
        var start = api.value(0);
        var end = api.value(1);
        var vol = api.value(2);
        var isPoc = api.value(3);
        var isVa = api.value(4);

        var x0 = api.coord([0, start])[0];
        var x1 = api.coord([vol, start])[0];
        var y0 = api.coord([0, start])[1];
        var y1 = api.coord([0, end])[1];

        var rect = echarts.graphic.clipRectByRect(
          {
            x: Math.min(x0, x1),
            y: Math.min(y0, y1) + 1,
            width: Math.abs(x1 - x0),
            height: Math.max(1, Math.abs(y1 - y0) - 2)
          },
          {
            x: params.coordSys.x,
            y: params.coordSys.y,
            width: params.coordSys.width,
            height: params.coordSys.height
          }
        );

        return rect && {
          type: 'rect',
          shape: rect,
          style: {
            fill: isPoc ? '#d14a61' : (isVa ? '#91cc75' : '#7aa6ff'),
            stroke: 'rgba(0,0,0,0.18)',
            lineWidth: 1
          }
        };
      },
      z: 3
    }
  ]
};
